head.script:
/**
 * 화 면 명 : 재고자산매각
 * 메뉴경로 : 회계/재무회계/고정자산/
 * ASIS경로 : /debis/dongwon-debis-engine/src/main/webapp/ac/fi/fixedaset/fi_301_03_01_n02b.jsp
 * 작 성 자 : 배기원
 * 작 업 일 : 2026-01-12
 * 작업내용 :
 *    1. 화면세팅
 *    2. 초기세팅(UDC), 그리드(데이터리스트)
 *    3. 스크립트 TOBE전환
 *    4. 기능확인(버튼)
 *    5. footer에 값 처리
 * 참고사항 : 
 *    1. 그리드ID.setNoResultMessageVisible(false) 설정해줘야 그리드에 데이터없음 안보임
 *    2. 선수금팝업 연결확인 필요(팝업화면 미개발[fm_502_03_00p.xml])
 *    3. 매각처리 후 매각취소를 하는 방법
 *       회계 > 재무회계 > 일반회계 > 전표관리 > 전표조회수정삭제 화면에서 전표삭제 처리(전표번호로 찾는게~)
 * 테스트데이터 :
 *    1. 조회조건 : 취득일자[20010101~20260127], 매각일자[20260313], 자산번호[1000012158], 매각여부[아니오]
 *       입력조건 : 증빙일자[20260313], 거래처[106-81-97118], 매출구분[02:수출], 증빙종류[영세율세금계산서][공제][기타]
 *                , 선수금액[0], 공급금액[1000], 부가세액[0], 부가세관리부서[00009:재경], 비고[테스트]
 *                , E-mail[pri0916@dongwon.com], 신고예외여부[미체크]
 *    2. 조회조건 : 취득일자[20120101~20131231], 매각일자[20260319], 매각여부[아니오]
 *       입력조건 : 증빙일자[20260319], 거래처[120-87-62427:동원로엑스(주)서남지사], 매출구분[01:일반], 증빙종류[10:세금계산서][1:공제][]
 *                , 선수금액[0], 공급금액[12000000], 부가세액[1200000], 부가세관리부서[00009:재경], 비고[테스트]
 *                , 신고예외여부[체크] : 체크 시 이메일 필수 아님
 * 수정이력 :
 *    - 2026-01-12      배기원    최초작성
 */
//hidden 값
scwin.txtCoClsCd  = "";     //회사구분코드(hidden, 회사팝업호출 시)
scwin.checkExchRt = "0";    //환율 부분 추가
