/**
 * TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
 */
scwin.onpageload = function() {
    scwin.memJson = $c.data.getMemInfo();
    scwin.vLoginCoCd     = $c.gus.cfIsNull(scwin.memJson["coCd"]) ? "" : scwin.memJson["coCd"];                     //소속자회사
    scwin.vLoginCoClsCd  = $c.gus.cfIsNull(scwin.memJson["coClsCd"]) ? "" : scwin.memJson["coClsCd"];               //회계_회사구분('CO035' : 0:동부 EXPRESS)
    scwin.vUserHomeClsCd = $c.gus.cfIsNull(scwin.memJson["userHomeClsCd"]) ? "" : scwin.memJson["userHomeClsCd"];   //사용자소속구분코드
    scwin.isSubCompany   = false;
    scwin.privAdmin      = $c.gus.cfIsNull(scwin.memJson["privAdmin"]) ? "" : scwin.memJson["privAdmin"];           //관리자권한
    scwin.user_id        = $c.gus.cfIsNull(scwin.memJson["userId"]) ? "" : scwin.memJson["userId"];                 //사용자ID

    const codeOptions = [
           { grpCd: "ZZ006", compID: "lc_crcCd, gr_master:crcCd", opt:{"range":"1"} } //통화코드
          ,{ grpCd: "FI088", compID: "acb_sellClsCd" }      //매출구분코드
          ,{ grpCd: "FI005", compID: "acb_deductClsCd" }    //공제구분
          ,{ grpCd: "FI004", compID: "lc_zeroTaxCls" }      //영세율구분
     ];
    $c.data.setCommonCode(codeOptions, scwin.callBackCommonCode);
};

/**
 * $c.data.setCommonCode 함수의 콜백함수
 */
scwin.callBackCommonCode = function() {
};


/**
 * 자산유형 조회
 * TOBE 추가
 */
scwin.f_submit_asetPattern = function() {
    //asis
    // ds_asetPattern.DataId = "/ac.fi.fixedaset.RetreiveFixedAsetPatternListCMD.do?useYn=1"
    // ds_asetPattern.undoAll();
    ds_asetPattern.removeAll();
    $c.sbm.execute(sbm_asetPattern, {"useYn":"1"});
    ds_asetPattern.sort("asetPatternCd", 0);
};


/**
 * 증빙종류 조회
 * TOBE 추가
 */
scwin.f_submit_evidClsCd = function() {
    // ds_evidClsCd.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC"
    //     + "&queryId=retrieveEvidInfo";
    // ds_evidClsCd.undoAll();
    ds_evidClsCd.removeAll();
    $c.sbm.execute(sbm_evidClsCd , {"sysCd":"CommonEBC", "queryId":"retrieveEvidInfo"});    
};


/**
 * 초기세팅(TOBE 그리드, 총건수)
 */
scwin.setInit = function() {
    gr_master.setNoResultMessageVisible(false);
    ds_master.reform();
    ds_master.removeAll();
    totalRows.setValue("0");
    scwin.checkExchRt = 0;
    ds_evidence.removeAll();
    ds_collMoney.removeAll();
    $c.gus.cfDisableBtnOnly([btn_save]);
};


/**
 * UDC값 초기화(scwin.onpageload 이후 세팅됨)
 */
scwin.onUdcCompleted = function() {
    // cfDisableKey();
    // f_SearchHeaderCreate(); //조회데이터셋 생성

    // //자산유형 조회
    // ds_asetPattern.DataId = "/ac.fi.fixedaset.RetreiveFixedAsetPatternListCMD.do?useYn=1"
    // ds_asetPattern.undoAll();
    // //증빙종류 조회
    // ds_evidClsCd.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC"
    //     + "&queryId=retrieveEvidInfo";
    // ds_evidClsCd.undoAll();

    // gr_master.headerHeight = 30;
    // cfDisableObjects([tbl_disp, tbl_evidence, ed_email]);
    // f_FieldClear();
    // f_setCompanyInfo();

    $c.gus.cfDisableKey();
    scwin.setInit();                //그리드초기화
    scwin.f_SearchHeaderCreate();   //TOBE사용안함
    scwin.f_submit_asetPattern();   //자산유형조회
    scwin.f_submit_evidClsCd();     //증빙종류조회

    $c.gus.cfDisableObjects([tbl_disp, tbl_evidence, ed_email]);
    scwin.f_SetSrchDefault();
    scwin.f_setCompanyInfo();
};


