/**
 * 조회필드 CLEAR
 */
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tbl_search, [ica_acqDtStDt, ica_acqDtEndDt, ica_procDt, ed_coCd, ed_coNm]);
