/**
 * 회사코드 팝업 callBack
 */
scwin.udc_comCode_callBackFunc = function (ret) {
    if (ret[0] != "N/A" && !$c.gus.cfIsNull(ret)) {
        //TODO : udc가 마지막으로 처리하다보니 초기값 귀속부서 빈값 안되도록 처리
        if(!$c.gus.cfIsNull(ed_coCd.hidVal) && !$c.gus.cfIsNull(scwin.txtCoClsCd)) {        
            // 조회조건 - 귀속부서 From
            $c.gus.cfInitObjects([ed_srchAcctDeptCd, ed_srchAcctDeptNm]);
        }
        ed_coCd.setValue(ret[0]);        // 코드
        ed_coNm.setValue(ret[5]);        // 회사명
        ed_coCd.hidVal = ret[0];         // 히든값
        scwin.txtCoClsCd = ret[1];       // 회사구분
    } else {
        ed_coCd.setValue("");            // 코드
        ed_coNm.setValue("");            // 회사명
        ed_coCd.hidVal   = "";           // 히든값
        scwin.txtCoClsCd = "";           // 회사구분
    }
    // 자회사 회계 시스템
    if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }
    if($c.gus.cfIsNull(scwin.initJson)) {
        scwin.initJson = dma_search.getJSON();
        // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우
        if ('T' == scwin.privAdmin || !scwin.isSubCompany) {
            $c.gus.cfEnableObjects([ed_coCd, ed_coNm, btn_company, btn_initAmt]);   // btn_initAmt: 선수금버튼
        } else {
            $c.gus.cfDisableObjects([ed_coCd, ed_coNm, btn_company, btn_initAmt]);  // btn_initAmt: 선수금버튼
        }
    }
};


/**
 * 조회
 */
scwin.f_Retrieve = async function () {
    let ret = await scwin.f_RetrieveValidate();
    if(!ret) {
        return;
    }

    // gr_master.setColumnDefaultValue('procYn', 'HeadCheck') = "false";
    // ds_evidence.removeAll();
    // ds_collMoney.removeAll();
    // ds_search.UseChangeInfo = false;
    scwin.setInit();
    dma_search.set("coClsCd", scwin.txtCoClsCd);
    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    gr_master.setNoResultMessageVisible(true);
    let rowCnt = ds_master.getRowCount();
    totalRows.setValue(rowCnt);

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        if (rowCnt == 0) {
            if($c.gus.cfCheckCreateFlag()) {
                $c.gus.cfTurnCreateFlag(false);
            }else {
                // 조회결과가 존재하지 않습니다
                $c.gus.cfAlertMsg(MSG_CM_WRN_002);
            }
            $c.gus.cfDisableObjects([tbl_disp, tbl_evidence]);
            acb_sellClsCd.setValue("");
            acb_evidClsCd.setValue("");
            acb_deductClsCd.setValue("");

        } else {
            //ds_evidence insert처리(단건임)
            scwin.f_EvidHeaderCreate();
            $c.gus.cfEnableObjects(tbl_evidence);
            $c.gus.cfDisableKey();
            $c.gus.cfDisableObjects([ed_email]);
            $c.gus.cfEnableBtnOnly([btn_save]);

            //조회된 결과 정렬(asis:<param name=SortExpr 참조)
            //<param name=SortExpr value="+asetPatternCd+fixedAsetNo">
            let options = {};
            options.sortIndex = "asetPatternCd fixedAsetNo";
            options.sortOrder = "1 1";
            ds_master.multisort(options);
            gr_master.setFocusedCell(0, 0);

            //매출증빙내역 영역 세팅
            acb_sellClsCd.setValue("02");	// 매출구분
            scwin.f_sellClsCd();	        // 매출구분 변경 시
            scwin.f_EvidClsCd();	        // 증빙구분 변경 시            
            acb_deductClsCd.setValue("1");	// 공제구분

            /**
             * for=lc_crcCd event=onSelChange() > f_crcCdChange()
             * 통화코드변경 시 환율부분 로직 추가
             */
            if(ds_master.getCellData(0, "crcCd") !=ACConstants.KOREA_WON) {
	            //환율 부분 추가
			    scwin.checkExchRt = ds_master.getCellData(0, "adptExchRt");
            }
        }
        //조회조건 자산유형
        $c.gus.cfDisableObjects([acb_asetPatternCd]);
    }
};

scwin.sbm_retrieve_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};


/**
 * 조회검증
 */
scwin.f_RetrieveValidate = async function() {
    /*if (ds_master.CountRow > 0 && ds_master.IsUpdated == true) {
    if (cfConfirmMsg(MSG_CM_CRM_005) == false)
    return;
    }*/
    let ret;
    if ($c.gus.cfIsNull(ica_acqDtStDt.getValue()) && $c.gus.cfIsNull(ica_acqDtEndDt.getValue())
        && $c.gus.cfIsNull(acb_asetPatternCd.getValue())
        && $c.gus.cfIsNull(ed_srchAcctDeptCd.getValue()) && $c.gus.cfIsNull(ed_srchAcctDeptNm.getValue())
        && $c.gus.cfIsNull(ed_srchFixedAsetNo.getValue())) {
        await $c.gus.cfAlertMsg("조회조건을 하나 이상 입력해 주세요.");
        ica_acqDtStDt.focus();
        return false;
    }

    ret = await $c.gus.cfValidate([tbl_search]);
    if (!ret) {
        return false;
    }

    //취득 일자 체크
    if ($c.gus.cfIsNull(ica_acqDtStDt.getValue()) && !$c.gus.cfIsNull(ica_acqDtEndDt.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["취득일자"]);
        ica_acqDtStDt.focus();
        return false;
    }

    if (!$c.gus.cfIsNull(ica_acqDtStDt.getValue()) && $c.gus.cfIsNull(ica_acqDtEndDt.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["취득일자"]);
        ica_acqDtEndDt.focus();
        return false;
    }

    if (!$c.gus.cfIsNull(ica_acqDtStDt.getValue()) && !$c.gus.cfIsNull(ica_acqDtEndDt.getValue())) {
        if (!await $c.gus.cfIsAfterDate(ica_acqDtStDt.getValue().trim(), ica_acqDtEndDt.getValue().trim())) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
            ica_acqDtStDt.focus();
            return false;
        }
    }
    //매각일자 확인(TOBE 추가)
    ret = await $c.date.isDate(ica_procDt.getValue().substring(0, 8));
    if(!ret) {
        await $c.win.alert("올바른 마감년월을(를) 입력하십시오.");
        ica_closeYm.focus();
        return;
    }

    return true;
};


