/**
 * 통화코드변경시
 */
scwin.f_crcCdChange = async function() {
    if ($c.gus.cfIsNull(lc_crcCd.getValue()) 
     || lc_crcCd.getValue() == ACConstants.KOREA_WON) {
        ed_adjustExchRt.setValue("0");
        ed_dispFornAmt.setValue("0");
        $c.gus.cfEnableObj(ed_dispFornAmt, false);
        $c.gus.cfEnableObj(ed_adjustExchRt, false);
        $c.gus.cfEnableObj(ed_amt, true);
        // ed_dispFornAmt.validExp = "외화금액:no:maxLength=13";
        lbl_dispFornAmt.removeClass("req");
        ed_dispFornAmt.setMandatory(false); 

    } else {
        // 자금의 환율테이블 조회(통화코드,작성일자)
        // 통화코드가 외화일경우 외화금액 필수
        $c.gus.cfEnableObjects(ed_adjustExchRt);
        $c.gus.cfEnableObj(ed_amt, false);
        // ed_dispFornAmt.validExp = "외화금액:yes:notAllowed=0&maxLength=13";
        lbl_dispFornAmt.addClass("req");
        ed_dispFornAmt.setMandatory(true);

        //통화코드 DataSet
        // tr_exchRt.Post();
        ds_exchRt.removeAll();
        dma_exchRtSearch.set("crcCd", lc_crcCd.getValue());
        dma_exchRtSearch.set("stdDt", ica_spplyDt.getValue());

        await $c.sbm.execute(sbm_exchRt);

        //환율 부분 추가(asis for=tr_exchRt event=OnSuccess())
        ed_adjustExchRt.setValue(ds_exchRt.getCellAllData(0, "stdExchRt"));
        $c.gus.cfEnableObj(ed_dispFornAmt, true);  
        scwin.checkExchRt = ds_master.getCellData(0, "adptExchRt");
        ed_dispFornAmt.focus();
    }
};


/**
 * 매출구분변경 시
 */
scwin.f_sellClsCd = function() {
    // 매출구분이 수출일 경우
    if (acb_sellClsCd.getValue() == "02") {
        acb_evidClsCd.setValue("20");
        $c.gus.cfDisableObjects([acb_evidClsCd]);
        // 매출구분이 일반일 경우
    } else if (acb_sellClsCd.getValue() == "01") {
        acb_evidClsCd.setValue("10");
        $c.gus.cfEnableObjects([acb_evidClsCd]);
    } else {
        acb_evidClsCd.setValue("10");
        $c.gus.cfEnableObjects([acb_evidClsCd]);
    }
    let rowPosition = ds_master.getRowPosition();
    if (ds_master.getCellData(rowPosition, "procYn") == "1") {
        ed_spplyAmt.setValue(ds_master.getCellData(rowPosition, "procAmt"));
    }

    //증빙구분[10:세금계산서, 20:영세율세금계산서]
    // 영세율세금계산서가 아니면 부가세액 10%
    if (acb_evidClsCd.getValue() == "20") {
        ed_vat.setValue("0");
    } else {
        //ed_vat.text = ed_spplyAmt.text * 0.1;  //버림->반올림 수정. 2012.07.09
        ed_vat.setValue(Math.round(ed_spplyAmt.getValue().trim() * 0.1));
    }
};


/**
 * 증빙구분변경시
 * ASIS : for=lc_evidClsCd event=OnSelChange2()
 */
scwin.f_EvidClsCd = function() {
    //증빙구분[10:세금계산서, 20:영세율세금계산서]
    //영세율세금계산서일경우
    if (acb_evidClsCd.getValue() == "20") {
        $c.gus.cfEnableObjects([lc_zeroTaxCls]);
        //영세율구분[1:일반, 2:기타]
        // lc_zeroTaxCls.index = 1;
        lc_zeroTaxCls.setValue("2");
        ed_vat.setValue("0");
        $c.gus.cfDisableObjects([ed_vat]);
    } else {
        // lc_zeroTaxCls.index = -1;
        lc_zeroTaxCls.setValue("");
        $c.gus.cfDisableObjects([lc_zeroTaxCls]);
        if ($c.gus.cfIsNull(acb_sellClsCd.getValue())) {
            $c.gus.cfDisableObjects([ed_vat]);
        } else {
            $c.gus.cfEnableObjects([ed_vat]);
        }
    }
    let rowPosition = ds_master.getRowPosition();
    if (ds_master.getCellData(rowPosition, "procYn") == "1") {
        ed_spplyAmt.setValue(ds_master.getCellData(rowPosition, "procAmt"));
    }

    // 영세율세금계산서가 아니면 부가세액 10%
    if (acb_evidClsCd.getValue() == "20") {
        ed_vat.setValue("0");
    } else {
        //ed_vat.text = ed_spplyAmt.text * 0.1;  //버림->반올림 수정. 2012.07.09
        ed_vat.setValue(Math.round(ed_spplyAmt.getValue().trim() * 0.1));
    }
};




