/**
 * DataList의 rowPosition이 변경된 경우 발생
 * for=ds_master event=OnRowPosChanged(row)
 */
scwin.ds_master_onrowpositionchange = async function (info) {
    if (ds_master.getRowCount() < 1) {
        return;
    }

    let newRow = info.newRowIndex;
    let oldRow = info.oldRowIndex;
    let procYn = ds_master.getCellData(newRow, "procYn");
    // let status = ds_master.getRowStatus(newRow);
    let statusCnt = ds_master.getModifiedIndex().length;

    if(procYn == "1") {
        $c.gus.cfDisableObjects([ed_dispFornAmt, ed_qty]);
        $c.gus.cfEnableObjects([ed_amt, lc_crcCd, ed_adjustExchRt]);
        /**
         * TOBE 로직 추가 : 통화코드가 원인 경우 환율[ed_adjustExchRt] 비활성화
         * TOBE는 scwin.lc_crcCd_onchange 값이 다른 경우만 탐
        */
        if(ds_master.getCellData(newRow, "crcCd") ==  ACConstants.KOREA_WON) {
            $c.gus.cfDisableObjects([ed_adjustExchRt]);
        }
    }else {
        $c.gus.cfDisableObjects([tbl_disp]);
    }

    /**
     * asis 가우스 이벤트 로직
     * for=ds_master event=CanRowPosChange(row)
     */
    if(procYn == "1" 
    && statusCnt > 0
    && scwin.sFlag == "Y" ) {
        let ret = await $c.win.confirm("행 변경 시 입력한 데이터가 초기화 됩니다.<BR>계속 진행하시겠습니까?");
        if(!ret) {
            ds_master.setEventPause("", true);
            gr_master.setFocusedCell(oldRow, 0);
            ds_master.setEventPause("", false);
            return;
        }
        ds_master.undoAll();
    }
};

/**
 * DataList의 하나의 셀에 대한 값이 변경된 경우 발생
 * ASIS for=ds_master event=OnColumnChanged(row,colid)
 */
scwin.ds_master_oncelldatachange = function (info) {
	// // 매각액이 변경 시
	// if (colid == "procAmt") {
	// 	ds_master.NameValue(row, "procDifferAmt") = ds_master.NameValue(row, "procAmt") - ds_master.NameValue(row, "acqAmt");
	// 	if (ds_master.NameValue(ds_master.RowPosition, "procYn") == "1") {
	// 		ed_spplyAmt.text = ds_master.NameValue(row, "procAmt");
	// 	}

	// 	// 영세율세금계산서가 아니면 부가세액 10%
	// 	if (lc_evidClsCd.BindColVal == "20") {
	// 		ed_vat.text = "0";
	// 	} else {
	// 		//ed_vat.text = ed_spplyAmt.text * 0.1;
	// 		ed_vat.text = Math.round(ed_spplyAmt.text.trim() *0.1); //버림->반올림 수정. 2012.07.09
	// 	}
	// }

	// // 환율 변경 시
	// if (colid == "adptExchRt") {
	// 	if (ds_master.NameValue(row, "dispFornAmt") != "") {
	// 		ed_amt.text = Math.round(ed_dispFornAmt.text.trim() * ed_adjustExchRt.text.trim());
	// 	}
	// }
    let colId = info.colID;
    let row   = info.rowIndex;

// console.log("scwin.ds_master_oncelldatachange > colId : "+ colId + ", row : "+row +", info.newValue : "+info.newValue);
	// 매각액이 변경 시
	if (colId == "procAmt") {
		ds_master.setCellData(row, "procDifferAmt", ds_master.getCellData(row, "procAmt") - ds_master.getCellData(row, "acqAmt"));
		if (ds_master.getCellData(row, "procYn") == "1") {
			ed_spplyAmt.setValue(info.newValue);
		}

		// 영세율세금계산서가 아니면 부가세액 10%
		if (acb_evidClsCd.getValue() == "20") {
			ed_vat.setValue("0");
		} else {
            //버림->반올림 수정. 2012.07.09
			ed_vat.setValue(Math.round(ed_spplyAmt.getValue().trim() * 0.1));
		}
	}

	// 환율 변경 시
	if (colId == "adptExchRt") {
		if (!$c.gus.cfIsNull(ds_master.getCellData(row, "dispFornAmt"))) {
			ed_amt.setValue(Math.round(ed_dispFornAmt.getValue().trim() * ed_adjustExchRt.getValue().trim()));
		}
	}
};

/**
 * 그리드의 콤보박스 라벨설정
 * customFormatter 옵션
 */
scwin.formatComboLabel = function(value, formattedValue, rowIdx, colIdx) {
    if($c.gus.cfIsNull(value)) {
        return "";
    }else {
        if(value == "1") {
            gr_master.setCellColor(rowIdx, "procYn", "blue");
        }else {
            gr_master.setCellColor(rowIdx, "procYn", "red");
        }

        return $c.gus.decode(value, "0", "예", "1", "아니오", "");
    }
};


